namespace App\Modules\Sirket\Requests;

use Illuminate\Foundation\Http\FormRequest;
use Illuminate\Validation\Rule;

class UpdateDepartmentRequest extends FormRequest
{
    public function authorize(): bool { return true; }

    public function rules(): array
    {
        $companyId = auth()->user()->company_id;
        $deptId    = $this->route('department')?->id;
        return [
            'name'                 => ['sometimes', 'required', 'string', 'max:191',
                Rule::unique('departments')->where('company_id', $companyId)->ignore($deptId)->whereNull('deleted_at')],
            'code'                 => 'nullable|string|max:50',
            'parent_department_id' => ['nullable', 'exists:departments,id',
                Rule::notIn([$deptId])],  // kendisi üst olamaz
            'manager_id'           => 'nullable|exists:personels,id',
            'is_active'            => 'nullable|boolean',
            'metadata'             => 'nullable|array',
        ];
    }
}
